 925 /// Intrinsic matchers.
 926 struct IntrinsicID_match {
 927   unsigned ID;
 928 
 929   IntrinsicID_match(Intrinsic::ID IntrID) : ID(IntrID) {}
 930 
 931   template <typename OpTy> bool match(OpTy *V) const {
 932     if (const auto *R = dyn_cast<VPWidenIntrinsicRecipe>(V))
 933       return R->getVectorIntrinsicID() == ID;
 934     if (const auto *R = dyn_cast<VPWidenCallRecipe>(V))
 935       return R->getCalledScalarFunction()->getIntrinsicID() == ID;
 936 
 937     auto MatchCalleeIntrinsic = [&](VPValue *CalleeOp) {
 938       if (!isa<VPIRValue>(CalleeOp))
 939         return false;
 940       auto *F = cast<Function>(CalleeOp->getLiveInIRValue());
 941       return F->getIntrinsicID() == ID;
 942     };
 943     if (const auto *R = dyn_cast<VPReplicateRecipe>(V))
 944       if (R->getOpcode() == Instruction::Call) {
 945         // The mask is always the last operand if predicated.
 946         return MatchCalleeIntrinsic(
 947             R->getOperand(R->getNumOperands() - 1 - R->isPredicated()));
 948       }
 949     if (const auto *R = dyn_cast<VPInstruction>(V))
 950       if (R->getOpcode() == Instruction::Call)
 951         return MatchCalleeIntrinsic(R->getOperand(R->getNumOperands() - 1));
