288   bool match(const VPRecipeBase *R) const {
289     if (std::tuple_size_v<Ops_t> == 0) {
290       auto *VPI = dyn_cast<VPInstruction>(R);
291       return VPI && VPI->getOpcode() == Opcode;
292     }
293 
294     if ((!matchRecipeAndOpcode<RecipeTys>(R) && ...))
295       return false;
296 
297     if (R->getNumOperands() < std::tuple_size<Ops_t>::value) {
298       [[maybe_unused]] auto *RepR = dyn_cast<VPReplicateRecipe>(R);
299       assert(((isa<VPInstruction>(R) &&
300                cast<VPInstruction>(R)->getNumOperandsForOpcode() == -1u) ||
301               (RepR && std::tuple_size_v<Ops_t> ==
302                            RepR->getNumOperands() - RepR->isPredicated())) &&
303              "non-variadic recipe with matched opcode does not have the "
304              "expected number of operands");
305       return false;
306     }
307 
308     // If the recipe has more operands than expected, we only support matching
309     // masked VPInstructions where the number of operands of the matcher is the
310     // same as the number of operands excluding mask.
311     if (R->getNumOperands() > std::tuple_size<Ops_t>::value) {
312       auto *VPI = dyn_cast<VPInstruction>(R);
313       if (!VPI || !VPI->isMasked() ||
314           VPI->getNumOperandsWithoutMask() != std::tuple_size<Ops_t>::value)
315         return false;
316     }
317 
318     auto IdxSeq = std::make_index_sequence<std::tuple_size<Ops_t>::value>();
319     if (all_of_tuple_elements(IdxSeq, [R](auto Op, unsigned Idx) {
320           return Op.match(R->getOperand(Idx));
321         }))
322       return true;
323 
324     return Commutative &&
325            all_of_tuple_elements(IdxSeq, [R](auto Op, unsigned Idx) {
326              return Op.match(R->getOperand(R->getNumOperands() - Idx - 1));
